const config = $input.first().json;
const sources = JSON.parse(config.sources_json || '[]');
return sources
  .filter((source) => source.active)
  .map((source) => ({
    json: {
      ...config,
      ...source,
      country: source.jurisdiction || config.country,
      jurisdiction: source.jurisdiction || config.country,
      registry_source_of_truth: config.registry_source_of_truth || 'docs/us_federal_official_sources.json'
    }
  }));

const item = $input.first().json;
const query = encodeURIComponent(item.federal_register_query || 'public contracts OR procurement OR acquisition');
const perPage = Number(item.max_api_results || 5);
const requestUrl = `https://www.federalregister.gov/api/v1/documents.json?per_page=${perPage}&conditions[term]=${query}&order=newest`;
return [{ json: { ...item, request_url: requestUrl } }];
